                source: naga::valid::TypeError::MissingCapability(Capabilities::COOPERATIVE_MATRIX),
                ..
            })
        );

        // Used as constructor
        check_extension_validation!(
            Capabilities::COOPERATIVE_MATRIX,
            &format!(
                r#"fn foo() {{
    let a = {ty}<f32, A>();
}}
"#,
            ),
            &format!(
