            source: valid::FunctionError::LocalVariable {
                name: local_var_name,
                source: valid::LocalVariableError::InvalidType(_),
                ..
            },
            ..
        })
        if local_var_name == "x"
    }

    // Rejected in statement lowering
    // There is a similar validator test in `validation.rs`.
    check(
