/// Constant evaluation with interesting values.
#[test]
fn const_eval_value_errors() {
    #[track_caller]
    fn variant(expr: &str) -> Result<naga::Module, naga::front::wgsl::ParseError> {
        let input = format!(
            r#"
                fn f() {{ _ = {expr}; }}
            "#
        );
        naga::front::wgsl::parse_str(&input)
