/// Naga should not crash just because the type of a
/// bad argument is a struct.
#[test]
fn struct_names_in_argument_errors() {
    #[track_caller]
    fn variant(argument: &str) -> Result<naga::Module, naga::front::wgsl::ParseError> {
        let input = format!(
            r#"
                struct A {{ x: i32, }};
                fn f() {{ _ = sin({argument}); }}
