    check_validation! {
        r#"
            struct NotVeryBigStruct {
                data: u32,
            }
            alias BigArrayOfStructs = array<NotVeryBigStruct, 1 << 29>;
        "#:
        Err(naga::valid::ValidationError::Layouter(
                naga::proc::LayoutError {
                    inner: naga::proc::LayoutErrorInner::TooLarge,
                    ..
                }
        ))
    }
}

