        r###"error: invalid field accessor `xyz`
  ┌─ wgsl:5:35
  │
5 │             let r : vec3<i32> = v.xyz;
  │                                   ^^^ invalid accessor

"###,
    );

    // 4-component swizzle from non-const vec3
    check(
        "
        @compute @workgroup_size(1)
        fn main() {
            var v = vec3<i32>();
            let r : vec4<i32> = v.xyzw;
        }
        ",
        r###"error: invalid field accessor `xyzw`
  ┌─ wgsl:5:35
  │
5 │             let r : vec4<i32> = v.xyzw;
  │                                   ^^^^ invalid accessor

"###,
    );
}

